mapper.select:
SELECT A.ID, A.DEPT_ID, A.ROLE_NAME, A.STATUS, A.DELETED, A.CREATE_BY, A.create_by_name, A.CREATE_TIME, A.UPDATE_BY, A.update_BY_NAME, A.UPDATE_TIME, A.ROLE_CODE, A.ROLE_SORT, CASE A.STATUS WHEN '1' THEN '在用' ELSE '停用' END STATUS_LABEL, A.MENU_CHECK_STRICTLY, A.DEPT_CHECK_STRICTLY, A.DATA_SCOPE, A.REMARK FROM SYS_ROLE A
and A.ROLE_NAME LIKE #{roleNm}
and A.ROLE_CODE LIKE #{roleCd}
and A.STATUS = #{status}
order by A.ROLE_SORT

SELECT A.ID, A.DEPT_ID, A.ROLE_NAME, A.STATUS, A.DELETED, A.CREATE_BY, A.create_by_name, A.CREATE_TIME, A.UPDATE_BY, A.update_BY_NAME, A.UPDATE_TIME, A.ROLE_CODE, A.ROLE_SORT, CASE A.STATUS WHEN '1' THEN '在用' ELSE '停用' END statusLabel, A.MENU_CHECK_STRICTLY, A.DEPT_CHECK_STRICTLY, A.DATA_SCOPE FROM SYS_ROLE A
and A.ROLE_NAME LIKE #{roleNm}
and A.ROLE_CODE LIKE #{roleCd}
and A.STATUS = #{status}
order by A.ROLE_SORT

mapper.update:
UPDATE sys_role SET ID = #{id, jdbcType=BIGINT}, DEPT_ID = #{deptId, jdbcType=BIGINT}, ROLE_NAME = #{roleName, jdbcType=VARCHAR}, STATUS = #{status, jdbcType=VARCHAR}, DELETED = #{deleted, jdbcType=VARCHAR}, ROLE_CODE = #{roleCode, jdbcType=VARCHAR}, ROLE_SORT = #{roleSort, jdbcType=BIGINT}, MENU_CHECK_STRICTLY = #{menuCheckStrictly, jdbcType=BIGINT}, DEPT_CHECK_STRICTLY = #{deptCheckStrictly, jdbcType=BIGINT}, DATA_SCOPE = #{dataScope, jdbcType=VARCHAR}, REMARK = #{remark, jdbcType=VARCHAR},
ROLE_CLASS = #{roleClass, jdbcType=VARCHAR},
DEPT_NAME = #{deptName, jdbcType=VARCHAR},
UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, update_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}
ID = #{id}

update
    sys_role
set
    status = #{status}
where
    id = #{id}

mapper.insert:
INSERT INTO SYS_ROLE_MENU ( MENU_ID, ROLE_ID ) SELECT menu_Id, role_Id from(
SELECT #{item, jdbcType=BIGINT} menu_ID, #{id, jdbcType=BIGINT} role_ID FROM DUAL
) T

INSERT INTO SYS_ROLE_DEPT ( dept_id, ROLE_ID, DEPT_NO ) SELECT dept_id, role_Id, dept_no from(
SELECT #{item, jdbcType=BIGINT} dept_id, #{roleId, jdbcType=BIGINT} role_ID, (select DEPT_NO from SYS_DEPT where dept_id = #{item, jdbcType=BIGINT}) DEPT_NO FROM DUAL
) T

INSERT INTO SYS_ROLE_USER ( USER_ID, ROLE_ID ) SELECT USER_ID, ROLE_ID from(
SELECT #{item, jdbcType=BIGINT} USER_ID, #{roleId, jdbcType=BIGINT} ROLE_ID FROM DUAL
) T

